// Normalizar entradas e definir defaults
const input = $input.first().json;

const query     = (input.query || '').trim();
const tipo      = (input.tipo  || 'cruzeiros').toLowerCase().trim();
const topK      = parseInt(input.top_ki) || (tipo === 'cruzeiros' ? 10 : 3);
const dataHoje  = $now.toFormat('dd/MM/yyyy');   // ex: 22/02/2026

// Validar tipo
const tipoFinal = ['cruzeiros','conhecimento'].includes(tipo) ? tipo : 'cruzeiros';

return [{
  json: {
    query_text:  query,
    tipo_busca:  tipoFinal,
    top_k:       topK,
    data_hoje:   dataHoje,
    tem_query:   query.length > 0
  }
}];

// Extrair embedding da resposta OpenAI e formatar como literal pgvector: [v1,v2,...]
const prepData    = $('Preparar Busca').item.json;
const httpResp    = $input.first().json;

let embeddingArr  = null;
let embeddingPG   = '';  // string no formato [0.1,0.2,...] para pgvector
let hasEmbedding  = false;

try {
  if (httpResp.data && httpResp.data[0] && httpResp.data[0].embedding) {
    embeddingArr  = httpResp.data[0].embedding;
    embeddingPG   = '[' + embeddingArr.join(',') + ']';
    hasEmbedding  = true;
  }
} catch (e) {
  // embedding não disponível – prossegue sem ele
}

return [{
  json: {
    ...prepData,
    embedding_pgvector: embeddingPG,   // '[0.1,0.2,...]'  ← usado no SQL
    has_embedding:      hasEmbedding
  }
}];

/*
 * Processar resultados PGVector para cruzeiros.
 * Regras do prompt original:
 *   - Se data de INÍCIO do cruzeiro for ANTERIOR a HOJE → ignorar completamente
 *   - Se dois eventos do mesmo artista: um passado e um futuro → retornar apenas o futuro
 */

// Dados de contexto do node Preparar Busca
const prep = $('Preparar Busca').item.json;

// Parse data de hoje: 'dd/MM/yyyy' → Date
function parseDataBR(str) {
  if (!str) return new Date();
  const [d, m, y] = str.split('/');
  return new Date(parseInt(y), parseInt(m) - 1, parseInt(d));
}
const hoje = parseDataBR(prep.data_hoje);

// Receber TODOS os itens retornados pelo Postgres
// n8n Postgres executeQuery retorna 1 item por linha de resultado
const items = $input.all();

const results = [];

for (const item of items) {
  const row = item.json;

  if (!row || !row.text) continue;

  // Parsear metadata (vem como string JSON ou objeto)
  let meta = {};
  try {
    meta = typeof row.metadata === 'string' ? JSON.parse(row.metadata) : (row.metadata || {});
  } catch(e) {}
  meta = meta.metadata;

  // Extrair data de início do cruzeiro para filtrar passados
  // Formatos possíveis nos metadados: "departure_date", "data_embarque", "date_nights" ("08/01/2026 - 03 noites")
  let dataEmbarque = null;

  if (meta.departure_date) {
    // Pode ser 'YYYY-MM-DD' ou 'DD/MM/YYYY'
    const s = meta.departure_date;
    if (s.includes('-')) {
      dataEmbarque = new Date(s);
    } else if (s.includes('/')) {
      dataEmbarque = parseDataBR(s);
    }
  }

  if (!dataEmbarque && meta.date_nights) {
    // Formato: "08/01/2026 - 03 noites"
    const match = meta.date_nights.match(/^(\d{2}\/\d{2}\/\d{4})/);
    if (match) dataEmbarque = parseDataBR(match[1]);
  }

  // ⚠️ Regra principal: ignorar cruzeiros com data ANTERIOR a hoje
  if (dataEmbarque && dataEmbarque < hoje) continue;

  results.push({
    navio:           meta.cruise_name    || meta.navio    || '',
    artista:         Array.isArray(meta.attractions) ? meta.attractions.join(', ') : (meta.attractions || meta.artista || ''),
    cabin_type:      meta.cabin_type     || meta.experience resource   || 'interna',
    price_pp_brl:    parseFloat(meta.price_pp_brl) || 0,
    total_price_brl: parseFloat(meta.total_price_brl) || 0,
    date_nights:     meta.date_nights    || '',
    data_embarque:   meta.departure_date || '',
    embark:          meta.embark         || 'Santos',
    score:           parseFloat(row.similarity_score) || 0,
    content:         row.text.substring(0, 300)
  });
}

// Desduplicar por artista: manter apenas o cruzeiro futuro mais próximo
const byArtista = {};
for (const r of results) {
  const key = r.artista.toLowerCase();
  if (!byArtista[key] || r.score > byArtista[key].score) {
    byArtista[key] = r;
  }
}
const deduped = Object.values(byArtista).sort((a, b) => b.score - a.score);

return [{
  json: {
    tipo:       'cruzeiros',
    query:      prep.query_text,
    data_hoje:  prep.data_hoje,
    resultados: results,
    total:      results.length
  }
}];

/*
 * Processar resultados PGVector para base de conhecimento.
 * Retorna documentos formatados com topic, subtopic, content, keywords e score.
 * Baseado nas regras da tool consultar_base_conhecimento do SDR original.
 */

const prep  = $('Preparar Busca').item.json;
const items = $input.all();

const results = [];

for (const item of items) {
  const row = item.json;
  if (!row || !row.text) continue;

  let meta = {};
  try {
    meta = typeof row.metadata === 'string' ? JSON.parse(row.metadata) : (row.metadata || {});
  } catch(e) {}

  results.push({
    doc_id:    meta.doc_id   || '',
    topic:     meta.topic    || meta.category || 'geral',
    subtopic:  meta.subtopic || '',
    title:     meta.title    || '',
    content:   row.text,
    keywords:  meta.keywords || [],
    aliases:   meta.aliases  || [],
    score:     parseFloat(row.similarity_score) || 0
  });
}

// Ordenar por relevância
results.sort((a, b) => b.score - a.score);

return [{
  json: {
    tipo:       'conhecimento',
    query:      prep.query_text,
    resultados: results,
    total:      results.length
  }
}];

return [{
  json: {
    tipo:       $('Preparar Busca').item.json.tipo_busca,
    query:      '',
    resultados: [],
    total:      0,
    message:    'Query vazia. Informe um termo de busca.'
  }
}];

/*
 * Formatar resposta final para consumo pelo agente LLM.
 * Converte os resultados em texto estruturado conforme as regras
 * dos prompts das tools originais (consulta_cruzeiros e consultar_base_conhecimento).
 */
const data       = $input.first().json;
const tipo       = data.tipo;
const resultados = data.resultados || [];
const query      = data.query || '';
const message    = data.message || '';

let textoFormatado = '';

if (tipo === 'cruzeiros') {

  if (resultados.length === 0) {
    textoFormatado = message ||
      `Nenhum cruzeiro disponível encontrado para: "${query}". ` +
      'Se quiser verificar outro artista ou período, informe o nome do cruzeiro.';
  } else {
    textoFormatado = `📋 Cruzeiros disponíveis para: "${query}"\n\n`;
    resultados.forEach((r, i) => {
      const total = r.total_price_brl > 0
        ? `  Total (${r.total_price_brl} pessoas): R$ ${r.total_price_brl.toLocaleString('pt-BR')}`
        : '';
      textoFormatado +=
        `${i + 1}. **${r.navio}**\n` +
        `  Artistas: ${r.artista || 'a confirmar'}\n` +
        `  experience resource: ${r.cabin_type} | R$ ${r.price_pp_brl.toLocaleString('pt-BR')} por pessoa\n` +
        `  Data: ${r.date_nights || r.data_embarque}\n` +
        `  Embarque: ${r.embark}\n` +
        (total ? total + '\n' : '') +
        `  Relevância: ${(r.score * 100).toFixed(0)}%\n\n`;
    });
  }

} else { // conhecimento

  if (resultados.length === 0) {
    textoFormatado = message ||
      `Não encontrei informação específica sobre: "${query}". ` +
      'Pode reformular a pergunta?';
  } else {
    textoFormatado = `📚 Base de conhecimento — "${query}"\n\n`;
    resultados.forEach((r, i) => {
      const titulo = r.title || r.topic || `Documento ${i + 1}`;
      textoFormatado +=
        `**${titulo}**\n` +
        `${r.content}\n\n`;
    });
  }
}

return [{
  json: {
    tipo,
    query,
    resultados,
    total:   resultados.length,
    output:  textoFormatado   // ← campo que o agente LLM lê como resposta da tool
  }
}];
